library(shiny)

# --- 定数（対戦相手データ） ---
OPPONENTS <- list(
  list(name = "のみ003", hp=1, atk=1, def=0, spd=98),
  list(name = "ラッシュやまのて", hp=34, atk=33, def=33, spd=0),
  list(name = "しらはまのすな", hp=28, atk=48, def=12, spd=12),
  list(name = "いかりのひでよし", hp=26, atk=36, def=36, spd=2),
  list(name = "うっ☆マンボ", hp=26, atk=38, def=32, spd=4)
)

# --- UI ---
ui <- fluidPage(
  tags$head(
    tags$style(HTML("
      /* 入力欄の上下矢印（スピンボタン）を削除 */
      input[type=number]::-webkit-inner-spin-button, 
      input[type=number]::-webkit-outer-spin-button { 
        -webkit-appearance: none; 
        margin: 0; 
      }
      input[type=number] { 
        -moz-appearance: textfield; 
      }

      .status-warning { color: red; font-weight: bold; margin-bottom: 10px; font-size: 0.85em; }
      .battle-log { 
        background-color: #f8f9fa; 
        border: 1px solid #ddd; 
        padding: 15px; 
        height: 600px; 
        overflow-y: auto; 
        font-family: 'Courier New', monospace; 
        white-space: pre-wrap; 
      }
      .footer-section { 
        margin-top: 20px; 
        padding: 15px; 
        border-top: 1px solid #eee; 
        background-color: #fafafa; 
        font-size: 0.9em;
      }
      .well { padding: 10px; margin-bottom: 5px; }
      h4 { margin-top: 5px; margin-bottom: 5px; font-size: 1.1em; }
      .shiny-input-container { margin-bottom: 5px !important; }
    ")),
    tags$script(HTML("
      $(document).on('shiny:connected', function() {
        setInterval(function() {
          $('.battle-log').each(function() {
            this.scrollTop = this.scrollHeight;
          });
        }, 100);
      });
    "))
  ),
  
  titlePanel("ステータス対戦 (JBSクエスト風)"),
  
  tabsetPanel(
    # モード1
    tabPanel("モード1: 5連勝チャレンジ",
             sidebarLayout(
               sidebarPanel(width = 4,
                            textInput("m1_name", "あなたのキャラクターの名前", ""),
                            numericInput("m1_hp", "HP", value = NA, min = 0),
                            numericInput("m1_atk", "攻撃力", value = NA, min = 0),
                            numericInput("m1_def", "守備力", value = NA, min = 0),
                            numericInput("m1_spd", "素早さ", value = NA, min = 0),
                            uiOutput("warning_m1"),
                            hr(),
                            actionButton("start_m1", "チャレンジ開始！", class = "btn-primary", width = "100%"),
                            uiOutput("next_btn_ui_m1")
               ),
               mainPanel(width = 8,
                         h4("対戦ログ"),
                         div(class = "battle-log", verbatimTextOutput("log_m1"))
               )
             )
    ),
    
    # モード2
    tabPanel("モード2: 自由対戦",
             sidebarLayout(
               sidebarPanel(width = 4,
                            fluidRow(
                              column(6, 
                                     h4("キャラ1"),
                                     textInput("m2_n1", "名前", ""),
                                     numericInput("m2_h1", "HP", value = NA),
                                     numericInput("m2_a1", "攻撃力", value = NA),
                                     numericInput("m2_d1", "守備力", value = NA),
                                     numericInput("m2_s1", "素早さ", value = NA),
                                     uiOutput("warning_m2_1")
                              ),
                              column(6, 
                                     h4("キャラ2"),
                                     textInput("m2_n2", "名前", ""),
                                     numericInput("m2_h2", "HP", value = NA),
                                     numericInput("m2_a2", "攻撃力", value = NA),
                                     numericInput("m2_d2", "守備力", value = NA),
                                     numericInput("m2_s2", "素早さ", value = NA),
                                     uiOutput("warning_m2_2")
                              )
                            ),
                            hr(),
                            actionButton("start_m2", "対戦開始！", class = "btn-success", width = "100%"),
                            uiOutput("next_btn_ui_m2")
               ),
               mainPanel(width = 8,
                         h4("対戦ログ"),
                         div(class = "battle-log", verbatimTextOutput("log_m2"))
               )
             )
    )
  ),
  
  div(class = "footer-section",
      fluidRow(
        column(6,
               strong("--- JBSクエスト風ゲーム ---"), br(),
               "対戦1：のみ003（第1回大会福岡代表）", br(),
               "対戦2：ラッシュやまのて（第1回大会準優勝）", br(),
               "対戦3：しらはまのすな（第2回大会準優勝）", br(),
               "対戦4：いかりのひでよし（第1回大会優勝）", br(),
               "対戦5：うっ☆マンボ（第2回大会優勝）"
        ),
        column(6,
               strong("参考資料:"), br(),
               tags$a(href="https://jbsmemorial.sakura.ne.jp/etc/quest1.html", "JBSメモリアル Quest1", target="_blank"), br(),
               tags$a(href="https://jbsmemorial.sakura.ne.jp/etc/quest2.html", "JBSメモリアル Quest2", target="_blank")
        )
      )
  )
)

# --- Server ---
server <- function(input, output, session) {
  battle_state <- reactiveValues(active = FALSE, mode = 0, c1 = NULL, c2 = NULL, turn = 1, opponent_idx = 1, log = "", finished = FALSE)
  
  get_warning <- function(name, hp, atk, def, spd) {
    if (name == "" || is.na(hp) || is.na(atk) || is.na(def) || is.na(spd)) return(div(class="status-warning", "全項目入力必須"))
    stats <- c(hp, atk, def, spd)
    if (sum(stats) > 100) return(div(class="status-warning", paste0("合計100超過(", sum(stats), ")")))
    if (hp <= 0) return(div(class="status-warning", "HPは1以上"))
    return(NULL)
  }
  
  output$warning_m1 <- renderUI({ get_warning(input$m1_name, input$m1_hp, input$m1_atk, input$m1_def, input$m1_spd) })
  output$warning_m2_1 <- renderUI({ get_warning(input$m2_n1, input$m2_h1, input$m2_a1, input$m2_d1, input$m2_s1) })
  output$warning_m2_2 <- renderUI({ get_warning(input$m2_n2, input$m2_h2, input$m2_a2, input$m2_d2, input$m2_s2) })
  
  execute_turn <- function() {
    c1 <- battle_state$c1; c2 <- battle_state$c2
    msg <- paste0("[ターン ", battle_state$turn, "]\n")
    order <- if ((c1$spd * runif(1)) > (c2$spd * runif(1))) list(c1, c2) else list(c2, c1)
    
    for (i in 1:2) {
      attacker <- order[[i]]; defender <- if(i==1) order[[2]] else order[[1]]
      if (attacker$hp <= 0) next
      if (runif(1, 0, 100) < defender$spd) {
        act <- "しかし かわされた！"
      } else {
        base_dmg <- (attacker$atk - (defender$def / 2)) / 2
        damage <- max(0, round(base_dmg + runif(1, -base_dmg/16, base_dmg/16)))
        defender$hp <- max(0, defender$hp - damage)
        act <- paste0(damage, " のダメージを与えた！")
      }
      if(defender$name == battle_state$c1$name) battle_state$c1$hp <- defender$hp else battle_state$c2$hp <- defender$hp
      msg <- paste0(msg, attacker$name, " の攻撃！ ", act, " (残りHP ", battle_state$c1$name, ":", battle_state$c1$hp, ", ", battle_state$c2$name, ":", battle_state$c2$hp, ")\n")
      if (battle_state$c1$hp <= 0 || battle_state$c2$hp <= 0) break
    }
    
    battle_state$log <- paste0(battle_state$log, msg, "\n")
    battle_state$turn <- battle_state$turn + 1
    
    if (battle_state$c1$hp <= 0 || battle_state$c2$hp <= 0) {
      battle_state$finished <- TRUE
      winner_name <- if(battle_state$c1$hp > 0) battle_state$c1$name else battle_state$c2$name
      battle_state$log <- paste0(battle_state$log, ">>>> ", winner_name, " の勝利！\n")
      
      if (battle_state$mode == 1) {
        if (winner_name == input$m1_name) {
          if (battle_state$opponent_idx == 5) {
            battle_state$log <- paste0(battle_state$log, "\n祝！！ 5連勝達成！ あなたが真の王者です！\n")
          }
        } else {
          battle_state$log <- paste0(battle_state$log, "\n残念！ 敗北しました。チャレンジ失敗です...\n")
        }
      }
    }
  }
  
  observeEvent(input$start_m1, {
    if (!is.null(get_warning(input$m1_name, input$m1_hp, input$m1_atk, input$m1_def, input$m1_spd))) return()
    battle_state$active <- TRUE; battle_state$mode <- 1; battle_state$opponent_idx <- 1
    battle_state$c1 <- list(name=input$m1_name, hp=input$m1_hp, atk=input$m1_atk, def=input$m1_def, spd=input$m1_spd)
    battle_state$c2 <- OPPONENTS[[1]]; battle_state$turn <- 1; battle_state$finished <- FALSE
    battle_state$log <- paste0("========== チャレンジ開始！ 第1戦 vs ", OPPONENTS[[1]]$name, " ==========\n\n")
  })
  
  observeEvent(input$start_m2, {
    if (!is.null(get_warning(input$m2_n1, input$m2_h1, input$m2_a1, input$m2_d1, input$m2_s1)) || 
        !is.null(get_warning(input$m2_n2, input$m2_h2, input$m2_a2, input$m2_d2, input$m2_s2))) return()
    battle_state$active <- TRUE; battle_state$mode <- 2
    battle_state$c1 <- list(name=input$m2_n1, hp=input$m2_h1, atk=input$m2_a1, def=input$m2_d1, spd=input$m2_s1)
    battle_state$c2 <- list(name=input$m2_n2, hp=input$m2_h2, atk=input$m2_a2, def=input$m2_d2, spd=input$m2_s2)
    battle_state$turn <- 1; battle_state$log <- "--- 自由対戦開始 ---\n\n"; battle_state$finished <- FALSE
  })
  
  observeEvent(input$next_turn, {
    if (!battle_state$finished) {
      execute_turn()
    } else if (battle_state$mode == 1 && battle_state$c1$hp > 0 && battle_state$opponent_idx < 5) {
      battle_state$opponent_idx <- battle_state$opponent_idx + 1
      battle_state$c1$hp <- input$m1_hp; battle_state$c2 <- OPPONENTS[[battle_state$opponent_idx]]
      battle_state$turn <- 1; battle_state$finished <- FALSE
      battle_state$log <- paste0(battle_state$log, "\n========== 第", battle_state$opponent_idx, "戦 vs ", battle_state$c2$name, " ==========\n\n")
    }
  })
  
  output$log_m1 <- renderText({ if(battle_state$mode == 1) battle_state$log else "" })
  output$log_m2 <- renderText({ if(battle_state$mode == 2) battle_state$log else "" })
  
  output$next_btn_ui_m1 <- renderUI({
    if(!battle_state$active || battle_state$mode != 1) return(NULL)
    if(battle_state$finished && battle_state$c1$hp <= 0) return(NULL)
    label <- if(battle_state$finished) "次の試合へ進む" else "次のターンへ"
    actionButton("next_turn", label, class = "btn-warning", style="margin-top:10px; width:100%;")
  })
  output$next_btn_ui_m2 <- renderUI({
    if(!battle_state$active || battle_state$mode != 2 || battle_state$finished) return(NULL)
    actionButton("next_turn", "次のターンへ", class = "btn-warning", style="margin-top:10px; width:100%;")
  })
}

shinyApp(ui = ui, server = server)
